Debug this logical structural case statement completely natively assigning completely un-synthesizable purely logic parameters.
module inverted_case(input [1:0] cur, output reg flag);
  always @(*) begin
    case(2'b11)
      cur + 1 : flag = 1;
      cur - 1 : flag = 0;
      default: flag  = 1;
    endcase
  end
endmodule

